const intent = $json.intent || '';
const params = $json.intentParams || {};
const accessToken = $json.accessToken || '';

if (!accessToken) {
  return [{ json: { ...$json, responseText: '⚠️ Google Auth failed: no access token.', success: false } }];
}

let endpoint, queryParams, method = 'GET', body = null;

if (intent === 'gmail_search') {
  endpoint = 'https://gmail.googleapis.com/gmail/v1/users/me/messages';
  queryParams = { maxResults: Math.min(params.max_results || 10, 50), q: params.q || '' };
} else if (intent === 'gmail_read') {
  if (!params.message_id) return [{ json: { ...$json, responseText: '❗ Required param missing: message_id', success: false } }];
  endpoint = `https://gmail.googleapis.com/gmail/v1/users/me/messages/${params.message_id}`;
  queryParams = { format: 'metadata', metadataHeaders: 'Subject,From,Date' };
} else if (intent === 'gmail_send') {
  if (!params.to) return [{ json: { ...$json, responseText: '❗ Required param missing: to', success: false } }];
  if (!params.subject) return [{ json: { ...$json, responseText: '❗ Required param missing: subject', success: false } }];
  if (!params.body) return [{ json: { ...$json, responseText: '❗ Required param missing: body', success: false } }];
  endpoint = 'https://gmail.googleapis.com/gmail/v1/users/me/messages/send';
  method = 'POST';
  const email = [
    `To: ${params.to}`,
    `Subject: ${params.subject}`,
    '',
    params.body
  ].join('\r\n');
  const raw = btoa(email).replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');
  body = { raw };
} else if (intent === 'gmail_delete') {
  if (!params.message_id) return [{ json: { ...$json, responseText: '❗ Required param missing: message_id', success: false } }];
  endpoint = `https://gmail.googleapis.com/gmail/v1/users/me/messages/${params.message_id}`;
  method = 'DELETE';
} else {
  return [{ json: { ...$json, responseText: '❓ Unknown Gmail intent: ' + intent, success: false } }];
}

return [{ json: { ...$json, apiEndpoint: endpoint, apiParams: queryParams, apiMethod: method, apiBody: body, bearerToken: accessToken, _ctx: { intent, params, accessToken, source: $json.source, userId: $json.userId, sessionId: $json.sessionId, inputText: $json.inputText } } }];

const ctx = $json._ctx || $('Build Request').first().json._ctx || {};
const messages = $json.messages || [];
if (messages.length === 0 && !$json.payload && !$json.id) {
  return [{ json: { ...ctx, responseText: '📩 No emails found.', success: true, intent: ctx.intent, intentParams: ctx.params } }];
}
let text = '';
if ($json.payload) {
  const headers = $json.payload.headers || [];
  const subject = headers.find(h => h.name === 'Subject')?.value || 'No Subject';
  const from = headers.find(h => h.name === 'From')?.value || 'Unknown';
  const date = headers.find(h => h.name === 'Date')?.value || '';
  text = `📨 <b>${subject}</b>\nFrom: ${from}\nDate: ${date}\n`;
} else if ($json.id && ($json.labelIds?.includes('SENT') || $json.resultSizeEstimate !== undefined)) {
  text = '✅ Email operation completed successfully.';
} else {
  text = '📩 Gmail Results:\n\n';
  messages.slice(0, 10).forEach((msg, i) => {
    text += `${i+1}. 📧 ${msg.id}\n`;
  });
  text += `\n📩 ${messages.length} email(s) found`;
}
return [{ json: { ...ctx, responseText: text, success: true, intent: ctx.intent, intentParams: ctx.params } }];

const ctx = $json._ctx || $('Build Request').first().json._ctx || {};
const jarvisLog = (level, message, meta = {}) => {
  const levels = { debug: 0, info: 1, warn: 2, error: 3 };
  const configLevel = ($env.LOG_LEVEL || 'info').toLowerCase();
  if (levels[level] >= (levels[configLevel] ?? 1)) {
    console[level === 'error' ? 'error' : level === 'warn' ? 'warn' : 'log'](
      JSON.stringify({ timestamp: new Date().toISOString(), level, traceId: ctx.sessionId || 'unknown', workflow: 'gmail-agent', message, meta })
    );
  }
};
const statusCode = $json.statusCode || $json.error?.statusCode || 0;
const statusMessage = $json.statusMessage || $json.error?.message || 'Unknown error';

if (statusCode === 401) {
  jarvisLog('warn', 'Token expired, attempting refresh', { intent: ctx.intent });
  try {
    const authRes = await $helpers.httpRequest({
      method: 'POST', url: 'https://oauth2.googleapis.com/token',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: 'client_id=' + encodeURIComponent($env.GOOGLE_CLIENT_ID) + '&client_secret=' + encodeURIComponent($env.GOOGLE_CLIENT_SECRET) + '&refresh_token=' + encodeURIComponent($env.GOOGLE_REFRESH_TOKEN) + '&grant_type=refresh_token',
      timeout: 15000
    });
    const retryRes = await $helpers.httpRequest({
      method: $('Build Request').first().json.apiMethod || 'GET',
      url: $('Build Request').first().json.apiEndpoint,
      headers: { 'Authorization': 'Bearer ' + authRes.access_token },
      body: $('Build Request').first().json.apiBody,
      timeout: 15000
    });
    return [{ json: { ...retryRes, _ctx: ctx } }];
  } catch (retryErr) {
    jarvisLog('error', 'Auth retry failed', { intent: ctx.intent, error: retryErr.message });
    return [{ json: { ...ctx, responseText: '⚠️ Authentication failed after refresh. Please re-authenticate Google OAuth.', success: false, intent: ctx.intent } }];
  }
}

jarvisLog('error', 'API request failed', { intent: ctx.intent, statusCode, statusMessage });
return [{ json: { ...ctx, responseText: '⚠️ Could not complete your request. API returned error ' + statusCode + ': ' + statusMessage + '. Please try again.', success: false, intent: ctx.intent, error: { statusCode, provider: 'gmail', intent: ctx.intent } } }];
